import{_ as t,o as s,c as i,ag as r}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"fr/getting-started/introduction.md","filePath":"fr/getting-started/introduction.md"}'),a={name:"fr/getting-started/introduction.md"};function n(o,e,d,l,u,c){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>MyCompanyDesk est une plateforme tout-en-un de comptabilite et de gestion d&#39;entreprise concue pour les freelances, les petites entreprises et les gestionnaires de biens locatifs. Elle vous aide a gerer l&#39;ensemble de votre flux financier -- de la creation de factures et du suivi des depenses a la declaration de TVA et a la gestion des relations clients.</p><h2 id="que-pouvez-vous-faire-avec-mycompanydesk" tabindex="-1">Que pouvez-vous faire avec MyCompanyDesk ? <a class="header-anchor" href="#que-pouvez-vous-faire-avec-mycompanydesk" aria-label="Permalink to &quot;Que pouvez-vous faire avec MyCompanyDesk ?&quot;">​</a></h2><ul><li><strong>Creer et envoyer des factures</strong> -- Factures professionnelles avec liens de paiement, generation de PDF et envoi par e-mail</li><li><strong>Suivre les depenses</strong> -- Enregistrez vos depenses manuellement ou numerisez des recus grace a l&#39;OCR alimente par l&#39;IA</li><li><strong>Gerer les clients</strong> -- Maintenez une base de donnees clients complete avec les coordonnees et l&#39;historique</li><li><strong>Generer des devis</strong> -- Creez des devis et convertissez-les en factures une fois acceptes</li><li><strong>Gerer des projets</strong> -- Organisez votre travail en projets, suivez le temps et surveillez la rentabilite</li><li><strong>Gerer les contrats</strong> -- Mettez en place des contrats de services ou de location recurrents</li><li><strong>Suivre les actifs</strong> -- Gerez les biens locatifs, vehicules et equipements</li><li><strong>Automatiser la facturation</strong> -- Configurez des factures et depenses recurrentes</li><li><strong>Consulter les rapports</strong> -- Chiffre d&#39;affaires, benefices, tresorerie, TVA et analyses clients</li><li><strong>Collaborer</strong> -- Invitez des membres d&#39;equipe, definissez les permissions et partagez avec votre comptable</li></ul><h2 id="langues-disponibles" tabindex="-1">Langues disponibles <a class="header-anchor" href="#langues-disponibles" aria-label="Permalink to &quot;Langues disponibles&quot;">​</a></h2><p>MyCompanyDesk est entierement disponible en :</p><ul><li>English</li><li>Nederlands (Dutch)</li><li>Deutsch (German)</li><li>Français (French)</li></ul><p>Vous pouvez changer de langue a tout moment depuis les parametres de votre profil. Les factures et les e-mails peuvent etre envoyes dans n&#39;importe laquelle de ces langues, independamment de la langue de votre interface.</p><h2 id="abonnements" tabindex="-1">Abonnements <a class="header-anchor" href="#abonnements" aria-label="Permalink to &quot;Abonnements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonctionnalite</th><th>Gratuit</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Factures et devis</td><td>Limite</td><td>Illimite</td><td>Illimite</td></tr><tr><td>Clients</td><td>Limite</td><td>Illimite</td><td>Illimite</td></tr><tr><td>Suivi des depenses</td><td>Basique</td><td>Complet</td><td>Complet</td></tr><tr><td>Numerisation de recus</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Suggestions IA</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Image de marque personnalisee</td><td>-</td><td>Oui</td><td>Oui</td></tr><tr><td>Membres d&#39;equipe</td><td>1</td><td>Jusqu&#39;a 5</td><td>Illimite</td></tr><tr><td>Rapports et export</td><td>Basique</td><td>Complet</td><td>Complet</td></tr><tr><td>Acces API</td><td>-</td><td>-</td><td>Oui</td></tr></tbody></table><h2 id="obtenir-de-l-aide" tabindex="-1">Obtenir de l&#39;aide <a class="header-anchor" href="#obtenir-de-l-aide" aria-label="Permalink to &quot;Obtenir de l&#39;aide&quot;">​</a></h2><ul><li>Utilisez le <strong>guide contextuel</strong> (l&#39;icone d&#39;aide dans l&#39;application) pour une assistance adaptee au contexte</li><li>Parcourez cette documentation pour des guides detailles des fonctionnalites</li><li>Contactez le support via le systeme de tickets integre a l&#39;application</li></ul><h2 id="prochaines-etapes" tabindex="-1">Prochaines etapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines etapes&quot;">​</a></h2><p>Pret a commencer ? Rendez-vous sur <a href="/fr/getting-started/create-account">Creer votre compte</a> pour configurer votre espace de travail.</p>',14)])])}const g=t(a,[["render",n]]);export{m as __pageData,g as default};
